import { MakeLogicType, actions, kea, path, reducers, selectors } from 'kea'

export interface ForegroundRegistration {
    providerId: string
    streamKey: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface foregroundStreamLogicValues {
    foregroundRegistrations: ForegroundRegistration[]
    foregroundStreamKey: string | null
    foregroundStreamKeys: Set<string>
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface foregroundStreamLogicActions {
    clearForegroundStream: (providerId: string) => {
        providerId: string
    }
    setForegroundStream: (
        streamKey: string,
        providerId: string
    ) => {
        providerId: string
        streamKey: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface foregroundStreamLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        foregroundStreamKeys: (foregroundRegistrations: ForegroundRegistration[]) => Set<string>
        foregroundStreamKey: (foregroundRegistrations: ForegroundRegistration[]) => string | null
    }
}

export type foregroundStreamLogicType = MakeLogicType<
    foregroundStreamLogicValues,
    foregroundStreamLogicActions,
    Record<string, any>,
    foregroundStreamLogicMeta
>

/**
 * Global registry of "foreground" streams — the runs currently rendered in surfaces the user is
 * watching and can respond in (the side panel, the full-page `/tasks` run view). Tool apply-back
 * reactions fire only for the most recent foreground stream (`foregroundStreamKey`), never for
 * background runs, passive embeds, or replayed history. A surface registers its `streamKey` under a
 * stable `providerId` on mount (and when it switches runs) and clears its own registration on
 * unmount, so co-mounted surfaces never clobber each other; the permission gate in `runStreamLogic`
 * checks membership in `foregroundStreamKeys`, while the tool-event bus reads `foregroundStreamKey`
 * to gate `foregroundOnly` subscriptions at delivery time.
 */
export const foregroundStreamLogic = kea<foregroundStreamLogicType>([
    path(['products', 'posthog_ai', 'frontend', 'logics', 'foregroundStreamLogic']),

    actions({
        setForegroundStream: (streamKey: string, providerId: string) => ({ streamKey, providerId }),
        clearForegroundStream: (providerId: string) => ({ providerId }),
    }),

    reducers({
        foregroundRegistrations: [
            [] as ForegroundRegistration[],
            {
                // Re-registering under the same provider replaces its entry and moves it to the end,
                // so the most recent registration always wins the `foregroundStreamKey` slot.
                setForegroundStream: (state, { streamKey, providerId }) => [
                    ...state.filter((r) => r.providerId !== providerId),
                    { providerId, streamKey },
                ],
                clearForegroundStream: (state, { providerId }) => state.filter((r) => r.providerId !== providerId),
            },
        ],
    }),

    selectors({
        /** Every stream currently registered by a watched, interactive surface. */
        foregroundStreamKeys: [
            (s) => [s.foregroundRegistrations],
            (registrations: ForegroundRegistration[]): Set<string> => new Set(registrations.map((r) => r.streamKey)),
        ],
        /** The most recently registered foreground stream — the apply-back target. */
        foregroundStreamKey: [
            (s) => [s.foregroundRegistrations],
            (registrations: ForegroundRegistration[]): string | null =>
                registrations.length > 0 ? registrations[registrations.length - 1].streamKey : null,
        ],
    }),
])
